import { copyFileSync, existsSync, lstatSync, mkdirSync, readdirSync, rmSync } from 'node:fs'
import { dirname, join, resolve } from 'node:path'

import type { ProjectEntry } from './config.js'

const DEV_TO_MEMORY_PATHS = [
